import{_ as e,o as i,c as r,S as t}from"./chunks/framework.C6RQlTYc.js";const u=JSON.parse('{"title":"反向传播","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_13-backpropagation.md","filePath":"直击概念/17ai/s_ai_13-backpropagation.md","lastUpdated":1778207238000}'),s={name:"直击概念/17ai/s_ai_13-backpropagation.md"};function n(l,a,o,d,h,p){return i(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="反向传播" tabindex="-1">反向传播 <a class="header-anchor" href="#反向传播" aria-label="Permalink to &quot;反向传播&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>反向传播（Backpropagation）是训练神经网络的核心算法，用于<strong>高效地计算损失函数相对于网络各层参数的梯度</strong>。有了梯度，才可以用梯度下降来更新参数。</p><p>核心思想：利用<strong>链式法则</strong>，将输出层的误差逐层反向传播到输入层，沿途计算每个参数的梯度。</p><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><h3 id="前向传播-forward-pass" tabindex="-1">前向传播（Forward Pass） <a class="header-anchor" href="#前向传播-forward-pass" aria-label="Permalink to &quot;前向传播（Forward Pass）&quot;">​</a></h3><p>数据从输入层经过各隐藏层，逐层计算，最终得到预测值和损失值：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>输入 → 层1 → 层2 → ... → 输出 → 损失</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="反向传播-backward-pass" tabindex="-1">反向传播（Backward Pass） <a class="header-anchor" href="#反向传播-backward-pass" aria-label="Permalink to &quot;反向传播（Backward Pass）&quot;">​</a></h3><p>从损失出发，沿网络反向逐层计算梯度：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>∂L/∂W⁽ⁿ⁾ = ∂L/∂a⁽ⁿ⁾ · ∂a⁽ⁿ⁾/∂z⁽ⁿ⁾ · ∂z⁽ⁿ⁾/∂W⁽ⁿ⁾</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>∂L/∂W：我们要的参数梯度</li><li>链式法则让梯度能从输出端一直算回输入端</li><li>每一层的梯度计算依赖上一层的计算结果</li></ul><h3 id="参数更新" tabindex="-1">参数更新 <a class="header-anchor" href="#参数更新" aria-label="Permalink to &quot;参数更新&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>W_new = W_old - learning_rate · ∂L/∂W</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="计算图-computation-graph" tabindex="-1">计算图（Computation Graph） <a class="header-anchor" href="#计算图-computation-graph" aria-label="Permalink to &quot;计算图（Computation Graph）&quot;">​</a></h2><p>现代深度学习框架（PyTorch、TensorFlow）使用<strong>计算图</strong>来自动求导：</p><ul><li>每个前向计算操作被记录为图的节点</li><li>反向传播时，自动沿图反向计算梯度</li><li>这就是<strong>自动微分（Autograd）</strong></li></ul><p>开发者不需要手动推导和实现反向传播公式。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="梯度消失-vanishing-gradient" tabindex="-1">梯度消失（Vanishing Gradient） <a class="header-anchor" href="#梯度消失-vanishing-gradient" aria-label="Permalink to &quot;梯度消失（Vanishing Gradient）&quot;">​</a></h3><p>深层网络中，梯度在反向传播时逐层减小，导致靠近输入层的参数几乎不更新。</p><ul><li><strong>原因</strong>：Sigmoid/Tanh 激活函数的导数 ≤ 1，多层相乘后趋近于 0</li><li><strong>解决</strong>：ReLU 激活函数、残差连接（ResNet）、层归一化</li></ul><h3 id="梯度爆炸-exploding-gradient" tabindex="-1">梯度爆炸（Exploding Gradient） <a class="header-anchor" href="#梯度爆炸-exploding-gradient" aria-label="Permalink to &quot;梯度爆炸（Exploding Gradient）&quot;">​</a></h3><p>梯度在反向传播时逐层放大，导致参数更新过大，模型无法收敛。</p><ul><li><strong>解决</strong>：梯度裁剪（Gradient Clipping）、权重初始化策略</li></ul><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>反向传播的本质是什么？为什么叫&quot;反向&quot;？</li><li>梯度消失和梯度爆炸如何解决？</li><li>PyTorch/TensorFlow 是如何自动计算梯度的？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://www.youtube.com/watch?v=Ilg3gGewQ5U" target="_blank" rel="noreferrer">Backpropagation - 3Blue1Brown</a></li><li><a href="https://cs231n.github.io/optimization-2/" target="_blank" rel="noreferrer">CS231n: Backpropagation</a></li></ul>',29)])])}const g=e(s,[["render",n]]);export{u as __pageData,g as default};
